  1→/**
  2→ * sequant run - Execute workflow for GitHub issues
  3→ *
  4→ * Orchestrator module that composes focused workflow modules:
  5→ * - worktree-manager: Worktree lifecycle (ensure, list, cleanup, changed files)
  6→ * - phase-executor: Phase execution with retry and failure handling
  7→ * - phase-mapper: Label-to-phase detection and workflow parsing
  8→ * - batch-executor: Batch execution, dependency sorting, issue logging
  9→ */
 10→
 11→import chalk from "chalk";
 12→import { spawnSync } from "child_process";
 13→import { getManifest } from "../lib/manifest.js";
 14→import { getSettings } from "../lib/settings.js";
 15→import { LogWriter } from "../lib/workflow/log-writer.js";
 16→import type { RunConfig } from "../lib/workflow/run-log-schema.js";
 17→import { StateManager } from "../lib/workflow/state-manager.js";
 18→import {
 19→  Phase,
 20→  DEFAULT_PHASES,
 21→  DEFAULT_CONFIG,
 22→  ExecutionConfig,
 23→  IssueResult,
 24→} from "../lib/workflow/types.js";
 25→import { ShutdownManager } from "../lib/shutdown.js";
 26→import { checkVersionCached, getVersionWarning } from "../lib/version-check.js";
 27→import { MetricsWriter } from "../lib/workflow/metrics-writer.js";
 28→import {
 29→  type MetricPhase,
 30→  determineOutcome,
 31→} from "../lib/workflow/metrics-schema.js";
 32→import { ui, colors } from "../lib/cli-ui.js";
 33→import { getCommitHash } from "../lib/workflow/git-diff-utils.js";
 34→import { getTokenUsageForRun } from "../lib/workflow/token-utils.js";
 35→import { reconcileStateAtStartup } from "../lib/workflow/state-utils.js";
 36→import { analyzeRun, formatReflection } from "../lib/workflow/run-reflect.js";
 37→
 38→// Extracted modules
 39→import {
 40→  detectDefaultBranch,
 41→  ensureWorktrees,
 42→  ensureWorktreesChain,
 43→  getWorktreeDiffStats,
 44→} from "../lib/workflow/worktree-manager.js";
 45→import type { WorktreeInfo } from "../lib/workflow/worktree-manager.js";
 46→import { formatDuration } from "../lib/workflow/phase-executor.js";
 47→import {
 48→  getIssueInfo,
 49→  sortByDependencies,
 50→  parseBatches,
 51→  getEnvConfig,
 52→  executeBatch,
 53→  runIssueWithLogging,
 54→} from "../lib/workflow/batch-executor.js";
 55→import type { RunOptions } from "../lib/workflow/batch-executor.js";
 56→
 57→// Re-export public API for backwards compatibility
 58→export {
 59→  parseQaVerdict,
 60→  formatDuration,
 61→  executePhaseWithRetry,
 62→} from "../lib/workflow/phase-executor.js";
 63→export {
 64→  detectDefaultBranch,
 65→  checkWorktreeFreshness,
 66→  removeStaleWorktree,
 67→  listWorktrees,
 68→  getWorktreeChangedFiles,
 69→  getWorktreeDiffStats,
 70→  readCacheMetrics,
 71→  filterResumedPhases,
 72→  ensureWorktree,
 73→  createCheckpointCommit,
 74→  reinstallIfLockfileChanged,
 75→  rebaseBeforePR,
 76→  createPR,
 77→} from "../lib/workflow/worktree-manager.js";
 78→export type {
 79→  WorktreeInfo,
 80→  RebaseResult,
 81→  PRCreationResult,
 82→} from "../lib/workflow/worktree-manager.js";
 83→export {
 84→  detectPhasesFromLabels,
 85→  parseRecommendedWorkflow,
 86→  determinePhasesForIssue,
 87→} from "../lib/workflow/phase-mapper.js";
 88→export {
 89→  getIssueInfo,
 90→  sortByDependencies,
 91→  parseBatches,
 92→  getEnvConfig,
 93→  executeBatch,
 94→  runIssueWithLogging,
 95→} from "../lib/workflow/batch-executor.js";
 96→export type { RunOptions } from "../lib/workflow/batch-executor.js";
 97→
 98→/**
 99→ * Main run command
100→ */
101→export async function runCommand(
102→  issues: string[],
103→  options: RunOptions,
104→): Promise<void> {
105→  console.log(ui.headerBox("SEQUANT WORKFLOW"));
106→
107→  // Version freshness check (cached, non-blocking, respects --quiet)
108→  if (!options.quiet) {
109→    try {
110→      const versionResult = await checkVersionCached();
111→      if (versionResult.isOutdated && versionResult.latestVersion) {
112→        console.log(
113→          chalk.yellow(
114→            `  ⚠️  ${getVersionWarning(versionResult.currentVersion, versionResult.latestVersion, versionResult.isLocalInstall)}`,
115→          ),
116→        );
117→        console.log("");
118→      }
119→    } catch {
120→      // Silent failure - version check is non-critical
121→    }
122→  }
123→
124→  // Check if initialized
125→  const manifest = await getManifest();
126→  if (!manifest) {
127→    console.log(
128→      chalk.red("❌ Sequant is not initialized. Run `sequant init` first."),
129→    );
130→    return;
131→  }
132→
133→  // Load settings and merge with environment config and CLI options
134→  const settings = await getSettings();
135→  const envConfig = getEnvConfig();
136→
137→  // Settings provide defaults, env overrides settings, CLI overrides all
138→  // Note: phases are auto-detected per-issue unless --phases is explicitly set
139→  // Commander.js converts --no-X to { X: false }, not { noX: true }.
140→  // Normalize these so RunOptions fields (noLog, noMcp, etc.) work correctly.
141→  // eslint-disable-next-line @typescript-eslint/no-explicit-any
142→  const cliOpts = options as any;
143→  const normalizedOptions: RunOptions = {
144→    ...options,
145→    ...(cliOpts.log === false && { noLog: true }),
146→    ...(cliOpts.smartTests === false && { noSmartTests: true }),
147→    ...(cliOpts.mcp === false && { noMcp: true }),
148→    ...(cliOpts.retry === false && { noRetry: true }),
149→    ...(cliOpts.rebase === false && { noRebase: true }),
150→    ...(cliOpts.pr === false && { noPr: true }),
151→  };
152→
153→  const mergedOptions: RunOptions = {
154→    // Settings defaults (phases removed - now auto-detected)
155→    sequential: normalizedOptions.sequential ?? settings.run.sequential,
156→    timeout: normalizedOptions.timeout ?? settings.run.timeout,
157→    logPath: normalizedOptions.logPath ?? settings.run.logPath,
158→    qualityLoop: normalizedOptions.qualityLoop ?? settings.run.qualityLoop,
159→    maxIterations:
160→      normalizedOptions.maxIterations ?? settings.run.maxIterations,
161→    noSmartTests: normalizedOptions.noSmartTests ?? !settings.run.smartTests,
162→    // Env overrides
163→    ...envConfig,
164→    // CLI explicit options override all
165→    ...normalizedOptions,
166→  };
167→
168→  // Determine if we should auto-detect phases from labels
169→  const autoDetectPhases = !options.phases && settings.run.autoDetectPhases;
170→  mergedOptions.autoDetectPhases = autoDetectPhases;
171→
172→  // Resolve base branch: CLI flag → settings.run.defaultBase → auto-detect → 'main'
173→  const resolvedBaseBranch =
174→    options.base ??
175→    settings.run.defaultBase ??
176→    detectDefaultBranch(mergedOptions.verbose ?? false);
177→
178→  // Parse issue numbers (or use batch mode)
179→  let issueNumbers: number[];
180→  let batches: number[][] | null = null;
181→
182→  if (mergedOptions.batch && mergedOptions.batch.length > 0) {
183→    batches = parseBatches(mergedOptions.batch);
184→    issueNumbers = batches.flat();
185→    console.log(
186→      chalk.gray(
187→        `  Batch mode: ${batches.map((b) => `[${b.join(", ")}]`).join(" → ")}`,
188→      ),
189→    );
190→  } else {
191→    issueNumbers = issues.map((i) => parseInt(i, 10)).filter((n) => !isNaN(n));
192→  }
193→
194→  if (issueNumbers.length === 0) {
195→    console.log(chalk.red("❌ No valid issue numbers provided."));
196→    console.log(chalk.gray("\nUsage: npx sequant run <issues...> [options]"));
197→    console.log(chalk.gray("Example: npx sequant run 1 2 3 --sequential"));
198→    console.log(
199→      chalk.gray('Batch example: npx sequant run --batch "1 2" --batch "3"'),
200→    );
201→    console.log(chalk.gray("Chain example: npx sequant run 1 2 3 --chain"));
202→    return;
203→  }
204→
205→  // Validate chain mode requirements
206→  if (mergedOptions.chain) {
207→    // Chain mode is inherently sequential — imply --sequential automatically
208→    if (!mergedOptions.sequential) {
209→      mergedOptions.sequential = true;
210→    }
211→
212→    if (batches) {
213→      console.log(chalk.red("❌ --chain cannot be used with --batch"));
214→      console.log(
215→        chalk.gray(
216→          "   Chain mode creates a linear dependency chain between issues.",
217→        ),
218→      );
219→      return;
220→    }
221→
222→    // Warn about long chains
223→    if (issueNumbers.length > 5) {
224→      console.log(
225→        chalk.yellow(
226→          `  ⚠️  Warning: Chain has ${issueNumbers.length} issues (recommended max: 5)`,
227→        ),
228→      );
229→      console.log(
230→        chalk.yellow(
231→          "     Long chains increase merge complexity and review difficulty.",
232→        ),
233→      );
234→      console.log(
235→        chalk.yellow(
236→          "     Consider breaking into smaller chains or using batch mode.",
237→        ),
238→      );
239→      console.log("");
240→    }
241→  }
242→
243→  // Validate QA gate requirements
244→  if (mergedOptions.qaGate && !mergedOptions.chain) {
245→    console.log(chalk.red("❌ --qa-gate requires --chain flag"));
246→    console.log(
247→      chalk.gray(
248→        "   QA gate ensures each issue passes QA before the next issue starts.",
249→      ),
250→    );
251→    console.log(
252→      chalk.gray(
253→        "   Usage: npx sequant run 1 2 3 --sequential --chain --qa-gate",
254→      ),
255→    );
256→    return;
257→  }
258→
259→  // Sort issues by dependencies (if more than one issue)
260→  if (issueNumbers.length > 1 && !batches) {
261→    const originalOrder = [...issueNumbers];
262→    issueNumbers = sortByDependencies(issueNumbers);
263→    const orderChanged = !originalOrder.every((n, i) => n === issueNumbers[i]);
264→    if (orderChanged) {
265→      console.log(
266→        chalk.gray(
267→          `  Dependency order: ${issueNumbers.map((n) => `#${n}`).join(" → ")}`,
268→        ),
269→      );
270→    }
271→  }
272→
273→  // Build config
274→  // Note: config.phases is only used when --phases is explicitly set or autoDetect fails
275→  const explicitPhases = mergedOptions.phases
276→    ? (mergedOptions.phases.split(",").map((p) => p.trim()) as Phase[])
277→    : null;
278→
279→  // Determine MCP enablement: CLI flag (--no-mcp) → settings.run.mcp → default (true)
280→  const mcpEnabled = mergedOptions.noMcp
281→    ? false
282→    : (settings.run.mcp ?? DEFAULT_CONFIG.mcp);
283→
284→  // Resolve retry setting: CLI flag → settings.run.retry → default (true)
285→  const retryEnabled = mergedOptions.noRetry
286→    ? false
287→    : (settings.run.retry ?? true);
288→
289→  const config: ExecutionConfig = {
290→    ...DEFAULT_CONFIG,
291→    phases: explicitPhases ?? DEFAULT_PHASES,
292→    sequential: mergedOptions.sequential ?? false,
293→    dryRun: mergedOptions.dryRun ?? false,
294→    verbose: mergedOptions.verbose ?? false,
295→    phaseTimeout: mergedOptions.timeout ?? DEFAULT_CONFIG.phaseTimeout,
296→    qualityLoop: mergedOptions.qualityLoop ?? false,
297→    maxIterations: mergedOptions.maxIterations ?? DEFAULT_CONFIG.maxIterations,
298→    noSmartTests: mergedOptions.noSmartTests ?? false,
299→    mcp: mcpEnabled,
300→    retry: retryEnabled,
301→    agent: mergedOptions.agent ?? settings.run.agent,
302→    aiderSettings: settings.run.aider,
303→  };
304→
305→  // Propagate verbose mode to UI config so spinners use text-only mode.
306→  // This prevents animated spinner control characters from colliding with
307→  // verbose console.log() calls from StateManager/MetricsWriter (#282).
308→  if (config.verbose) {
309→    ui.configure({ verbose: true });
310→  }
311→
312→  // Initialize log writer if JSON logging enabled
313→  // Default: enabled via settings (logJson: true), can be disabled with --no-log
314→  let logWriter: LogWriter | null = null;
315→  const shouldLog =
316→    !mergedOptions.noLog &&
317→    !config.dryRun &&
318→    (mergedOptions.logJson ?? settings.run.logJson);
319→
320→  if (shouldLog) {
321→    const runConfig: RunConfig = {
322→      phases: config.phases,
323→      sequential: config.sequential,
324→      qualityLoop: config.qualityLoop,
325→      maxIterations: config.maxIterations,
326→      chain: mergedOptions.chain,
327→      qaGate: mergedOptions.qaGate,
328→    };
329→
330→    try {
331→      logWriter = new LogWriter({
332→        logPath: mergedOptions.logPath ?? settings.run.logPath,
333→        verbose: config.verbose,
334→        startCommit: getCommitHash(process.cwd()),
335→      });
336→      await logWriter.initialize(runConfig);
337→    } catch (err) {
338→      // Log initialization failure is non-fatal - warn and continue without logging
339→      // Common causes: permissions issues, disk full, invalid path
340→      const errorMessage = err instanceof Error ? err.message : String(err);
341→      console.log(
342→        chalk.yellow(
343→          `  ⚠️ Log initialization failed, continuing without logging: ${errorMessage}`,
344→        ),
345→      );
346→      logWriter = null;
347→    }
348→  }
349→
350→  // Initialize state manager for persistent workflow state tracking
351→  // State tracking is always enabled (unless dry run)
352→  let stateManager: StateManager | null = null;
353→  if (!config.dryRun) {
354→    stateManager = new StateManager({ verbose: config.verbose });
355→  }
356→
357→  // Initialize shutdown manager for graceful interruption handling
358→  const shutdown = new ShutdownManager();
359→
360→  // Register log writer finalization as cleanup task
361→  if (logWriter) {
362→    const writer = logWriter; // Capture for closure
363→    shutdown.registerCleanup("Finalize run logs", async () => {
364→      await writer.finalize();
365→    });
366→  }
367→
368→  // Display configuration
369→  console.log(chalk.gray(`  Stack: ${manifest.stack}`));
370→  if (autoDetectPhases) {
371→    console.log(chalk.gray(`  Phases: auto-detect from labels`));
372→  } else {
373→    console.log(chalk.gray(`  Phases: ${config.phases.join(" → ")}`));
374→  }
375→  console.log(
376→    chalk.gray(
377→      `  Mode: ${config.sequential ? "stop-on-failure" : "continue-on-failure"}`,
378→    ),
379→  );
380→  if (config.qualityLoop) {
381→    console.log(
382→      chalk.gray(
383→        `  Quality loop: enabled (max ${config.maxIterations} iterations)`,
384→      ),
385→    );
386→  }
387→  if (mergedOptions.testgen) {
388→    console.log(chalk.gray(`  Testgen: enabled`));
389→  }
390→  if (config.noSmartTests) {
391→    console.log(chalk.gray(`  Smart tests: disabled`));
392→  }
393→  if (config.dryRun) {
394→    console.log(chalk.yellow(`  ⚠️  DRY RUN - no actual execution`));
395→  }
396→  if (logWriter) {
397→    console.log(
398→      chalk.gray(
399→        `  Logging: JSON (run ${logWriter.getRunId()?.slice(0, 8)}...)`,
400→      ),
401→    );
402→  }
403→  if (stateManager) {
404→    console.log(chalk.gray(`  State tracking: enabled`));
405→  }
406→  if (mergedOptions.force) {
407→    console.log(chalk.yellow(`  Force mode: enabled (bypass state guard)`));
408→  }
409→  console.log(
410→    chalk.gray(`  Issues: ${issueNumbers.map((n) => `#${n}`).join(", ")}`),
411→  );
412→
413→  // ============================================================================
414→  // Pre-flight State Guard (#305)
415→  // ============================================================================
416→
417→  // AC-5: Auto-cleanup at run start - reconcile stale ready_for_merge states
418→  if (stateManager && !config.dryRun) {
419→    try {
420→      const reconcileResult = await reconcileStateAtStartup({
421→        verbose: config.verbose,
422→      });
423→
424→      if (reconcileResult.success && reconcileResult.advanced.length > 0) {
425→        console.log(
426→          chalk.gray(
427→            `  State reconciled: ${reconcileResult.advanced.map((n) => `#${n}`).join(", ")} → merged`,
428→          ),
429→        );
430→      }
431→    } catch {
432→      // AC-8: Graceful degradation - don't block execution on reconciliation failure
433→      if (config.verbose) {
434→        console.log(
435→          chalk.yellow(`  ⚠️  State reconciliation failed, continuing...`),
436→        );
437→      }
438→    }
439→  }
440→
441→  // AC-1 & AC-2: Pre-flight state guard - skip completed issues unless --force
442→  if (stateManager && !config.dryRun && !mergedOptions.force) {
443→    const skippedIssues: number[] = [];
444→    const activeIssues: number[] = [];
445→
446→    for (const issueNumber of issueNumbers) {
447→      try {
448→        const issueState = await stateManager.getIssueState(issueNumber);
449→        if (
450→          issueState &&
451→          (issueState.status === "ready_for_merge" ||
452→            issueState.status === "merged")
453→        ) {
454→          skippedIssues.push(issueNumber);
455→          console.log(
456→            chalk.yellow(
457→              `  ⚠️  #${issueNumber}: already ${issueState.status} — skipping (use --force to re-run)`,
458→            ),
459→          );
460→        } else {
461→          activeIssues.push(issueNumber);
462→        }
463→      } catch {
464→        // AC-8: Graceful degradation - if state check fails, include the issue
465→        activeIssues.push(issueNumber);
466→      }
467→    }
468→
469→    // Update issueNumbers to only include active issues
470→    if (skippedIssues.length > 0) {
471→      issueNumbers = activeIssues;
472→
473→      if (issueNumbers.length === 0) {
474→        console.log(
475→          chalk.yellow(
476→            `\n  All issues already completed. Use --force to re-run.`,
477→          ),
478→        );
479→        return;
480→      }
481→
482→      console.log(
483→        chalk.gray(
484→          `  Active issues: ${issueNumbers.map((n) => `#${n}`).join(", ")}`,
485→        ),
486→      );
487→    }
488→  }
489→
490→  // Worktree isolation is enabled by default for multi-issue runs
491→  const useWorktreeIsolation =
492→    mergedOptions.worktreeIsolation !== false && issueNumbers.length > 0;
493→
494→  if (useWorktreeIsolation) {
495→    console.log(chalk.gray(`  Worktree isolation: enabled`));
496→  }
497→  if (resolvedBaseBranch) {
498→    console.log(chalk.gray(`  Base branch: ${resolvedBaseBranch}`));
499→  }
500→  if (mergedOptions.chain) {
501→    console.log(
502→      chalk.gray(`  Chain mode: enabled (each issue branches from previous)`),
503→    );
504→  }
505→  if (mergedOptions.qaGate) {
506→    console.log(chalk.gray(`  QA gate: enabled (chain waits for QA pass)`));
507→  }
508→
509→  // Fetch issue info for all issues first
510→  const issueInfoMap = new Map<number, { title: string; labels: string[] }>();
511→  for (const issueNumber of issueNumbers) {
512→    issueInfoMap.set(issueNumber, await getIssueInfo(issueNumber));
513→  }
514→
515→  // Create worktrees for all issues before execution (if isolation enabled)
516→  let worktreeMap: Map<number, WorktreeInfo> = new Map();
517→  if (useWorktreeIsolation && !config.dryRun) {
518→    const issueData = issueNumbers.map((num) => ({
519→      number: num,
520→      title: issueInfoMap.get(num)?.title || `Issue #${num}`,
521→    }));
522→
523→    // Use chain mode or standard worktree creation
524→    if (mergedOptions.chain) {
525→      worktreeMap = await ensureWorktreesChain(
526→        issueData,
527→        config.verbose,
528→        manifest.packageManager,
529→        resolvedBaseBranch,
530→      );
531→    } else {
532→      worktreeMap = await ensureWorktrees(
533→        issueData,
534→        config.verbose,
535→        manifest.packageManager,
536→        resolvedBaseBranch,
537→      );
538→    }
539→
540→    // Register cleanup tasks for newly created worktrees (not pre-existing ones)
541→    for (const [issueNum, worktree] of worktreeMap.entries()) {
542→      if (!worktree.existed) {
543→        shutdown.registerCleanup(
544→          `Cleanup worktree for #${issueNum}`,
545→          async () => {
546→            // Remove worktree (leaves branch intact for recovery)
547→            const result = spawnSync(
548→              "git",
549→              ["worktree", "remove", "--force", worktree.path],
550→              {
551→                stdio: "pipe",
552→              },
553→            );
554→            if (result.status !== 0 && config.verbose) {
555→              console.log(
556→                chalk.yellow(
557→                  `    Warning: Could not remove worktree ${worktree.path}`,
558→                ),
559→              );
560→            }
561→          },
562→        );
563→      }
564→    }
565→  }
566→
567→  // Execute with graceful shutdown handling
568→  const results: IssueResult[] = [];
569→  let exitCode = 0;
570→
571→  try {
572→    if (batches) {
573→      // Batch execution: run batches sequentially, issues within batch based on mode
574→      for (let batchIdx = 0; batchIdx < batches.length; batchIdx++) {
575→        const batch = batches[batchIdx];
576→        console.log(
577→          chalk.blue(
578→            `\n  Batch ${batchIdx + 1}/${batches.length}: Issues ${batch.map((n) => `#${n}`).join(", ")}`,
579→          ),
580→        );
581→
582→        const batchResults = await executeBatch(
583→          batch,
584→          config,
585→          logWriter,
586→          stateManager,
587→          mergedOptions,
588→          issueInfoMap,
589→          worktreeMap,
590→          shutdown,
591→          manifest.packageManager,
592→          resolvedBaseBranch,
593→        );
594→        results.push(...batchResults);
595→
596→        // Check if batch failed and we should stop
597→        const batchFailed = batchResults.some((r) => !r.success);
598→        if (batchFailed && config.sequential) {
599→          console.log(
600→            chalk.yellow(
601→              `\n  ⚠️  Batch ${batchIdx + 1} failed, stopping batch execution`,
602→            ),
603→          );
604→          break;
605→        }
606→      }
607→    } else if (config.sequential) {
608→      // Sequential execution
609→      for (let i = 0; i < issueNumbers.length; i++) {
610→        const issueNumber = issueNumbers[i];
611→        const issueInfo = issueInfoMap.get(issueNumber) ?? {
612→          title: `Issue #${issueNumber}`,
613→          labels: [],
614→        };
615→        const worktreeInfo = worktreeMap.get(issueNumber);
616→
617→        // Start issue logging
618→        if (logWriter) {
619→          logWriter.startIssue(issueNumber, issueInfo.title, issueInfo.labels);
620→        }
621→
622→        const result = await runIssueWithLogging(
623→          issueNumber,
624→          config,
625→          logWriter,
626→          stateManager,
627→          issueInfo.title,
628→          issueInfo.labels,
629→          mergedOptions,
630→          worktreeInfo?.path,
631→          worktreeInfo?.branch,
632→          shutdown,
633→          mergedOptions.chain, // Enable checkpoint commits in chain mode
634→          manifest.packageManager,
635→          // In chain mode, only the last issue should trigger pre-PR rebase
636→          mergedOptions.chain ? i === issueNumbers.length - 1 : undefined,
637→          resolvedBaseBranch,
638→        );
639→        results.push(result);
640→
641→        // Record PR info in log before completing issue
642→        if (logWriter && result.prNumber && result.prUrl) {
643→          logWriter.setPRInfo(result.prNumber, result.prUrl);
644→        }
645→
646→        // Complete issue logging
647→        if (logWriter) {
648→          logWriter.completeIssue();
649→        }
650→
651→        // Check if shutdown was triggered
652→        if (shutdown.shuttingDown) {
653→          break;
654→        }
655→
656→        if (!result.success) {
657→          // Check if QA gate is enabled and QA specifically failed
658→          if (mergedOptions.qaGate) {
659→            const qaResult = result.phaseResults.find((p) => p.phase === "qa");
660→            const qaFailed = qaResult && !qaResult.success;
661→
662→            if (qaFailed) {
663→              // QA gate: pause chain with clear messaging
664→              console.log(chalk.yellow("\n  ⏸️  QA Gate"));
665→              console.log(
666→                chalk.yellow(
667→                  `     Issue #${issueNumber} QA did not pass. Chain paused.`,
668→                ),
669→              );
670→              console.log(
671→                chalk.gray(
672→                  "     Fix QA issues and re-run, or run /loop to auto-fix.",
673→                ),
674→              );
675→
676→              // Update state to waiting_for_qa_gate
677→              if (stateManager) {
678→                try {
679→                  await stateManager.updateIssueStatus(
680→                    issueNumber,
681→                    "waiting_for_qa_gate",
682→                  );
683→                } catch {
684→                  // State tracking errors shouldn't stop execution
685→                }
686→              }
687→              break;
688→            }
689→          }
690→
691→          const chainInfo = mergedOptions.chain ? " (chain stopped)" : "";
692→          console.log(
693→            chalk.yellow(
694→              `\n  ⚠️  Issue #${issueNumber} failed, stopping sequential execution${chainInfo}`,
695→            ),
696→          );
697→          break;
698→        }
699→      }
700→    } else {
701→      // Default mode: run issues serially but continue on failure (don't stop)
702→      // TODO: Add proper parallel execution with listr2
703→      for (const issueNumber of issueNumbers) {
704→        // Check if shutdown was triggered
705→        if (shutdown.shuttingDown) {
706→          break;
707→        }
708→
709→        const issueInfo = issueInfoMap.get(issueNumber) ?? {
710→          title: `Issue #${issueNumber}`,
711→          labels: [],
712→        };
713→        const worktreeInfo = worktreeMap.get(issueNumber);
714→
715→        // Start issue logging
716→        if (logWriter) {
717→          logWriter.startIssue(issueNumber, issueInfo.title, issueInfo.labels);
718→        }
719→
720→        const result = await runIssueWithLogging(
721→          issueNumber,
722→          config,
723→          logWriter,
724→          stateManager,
725→          issueInfo.title,
726→          issueInfo.labels,
727→          mergedOptions,
728→          worktreeInfo?.path,
729→          worktreeInfo?.branch,
730→          shutdown,
731→          false, // Parallel mode doesn't support chain
732→          manifest.packageManager,
733→          undefined,
734→          resolvedBaseBranch,
735→        );
736→        results.push(result);
737→
738→        // Record PR info in log before completing issue
739→        if (logWriter && result.prNumber && result.prUrl) {
740→          logWriter.setPRInfo(result.prNumber, result.prUrl);
741→        }
742→
743→        // Complete issue logging
744→        if (logWriter) {
745→          logWriter.completeIssue();
746→        }
747→      }
748→    }
749→
750→    // Finalize log
751→    let logPath: string | null = null;
752→    if (logWriter) {
753→      logPath = await logWriter.finalize({
754→        endCommit: getCommitHash(process.cwd()),
755→      });
756→    }
757→
758→    // Calculate success/failure counts
759→    const passed = results.filter((r) => r.success).length;
760→    const failed = results.filter((r) => !r.success).length;
761→
762→    // Record metrics (local analytics)
763→    if (!config.dryRun && results.length > 0) {
764→      try {
765→        const metricsWriter = new MetricsWriter({ verbose: config.verbose });
766→
767→        // Calculate total duration
768→        const totalDuration = results.reduce(
769→          (sum, r) => sum + (r.durationSeconds ?? 0),
770→          0,
771→        );
772→
773→        // Get unique phases from all results
774→        const allPhases = new Set<MetricPhase>();
775→        for (const result of results) {
776→          for (const phaseResult of result.phaseResults) {
777→            // Only include phases that are valid MetricPhases
778→            const phase = phaseResult.phase as MetricPhase;
779→            if (
780→              [
781→                "spec",
782→                "security-review",
783→                "testgen",
784→                "exec",
785→                "test",
786→                "qa",
787→                "loop",
788→              ].includes(phase)
789→            ) {
790→              allPhases.add(phase);
791→            }
792→          }
793→        }
794→
795→        // Calculate aggregate metrics from worktrees
796→        let totalFilesChanged = 0;
797→        let totalLinesAdded = 0;
798→        let totalQaIterations = 0;
799→
800→        for (const result of results) {
801→          const worktreeInfo = worktreeMap.get(result.issueNumber);
802→          if (worktreeInfo?.path) {
803→            const stats = getWorktreeDiffStats(worktreeInfo.path);
804→            totalFilesChanged += stats.filesChanged;
805→            totalLinesAdded += stats.linesAdded;
806→          }
807→          // Count QA iterations (loop phases indicate retries)
808→          if (result.loopTriggered) {
809→            totalQaIterations += result.phaseResults.filter(
810→              (p) => p.phase === "loop",
811→            ).length;
812→          }
813→        }
814→
815→        // Build CLI flags for metrics
816→        const cliFlags: string[] = [];
817→        if (mergedOptions.sequential) cliFlags.push("--sequential");
818→        if (mergedOptions.chain) cliFlags.push("--chain");
819→        if (mergedOptions.qaGate) cliFlags.push("--qa-gate");
820→        if (mergedOptions.qualityLoop) cliFlags.push("--quality-loop");
821→        if (mergedOptions.testgen) cliFlags.push("--testgen");
822→
823→        // Read token usage from SessionEnd hook files (AC-5, AC-6)
824→        const tokenUsage = getTokenUsageForRun(undefined, true); // cleanup after reading
825→
826→        // Record the run
827→        await metricsWriter.recordRun({
828→          issues: issueNumbers,
829→          phases: Array.from(allPhases),
830→          outcome: determineOutcome(passed, results.length),
831→          duration: totalDuration,
832→          model: process.env.ANTHROPIC_MODEL ?? "opus",
833→          flags: cliFlags,
834→          metrics: {
835→            tokensUsed: tokenUsage.tokensUsed,
836→            filesChanged: totalFilesChanged,
837→            linesAdded: totalLinesAdded,
838→            acceptanceCriteria: 0, // Would need to parse from issue
839→            qaIterations: totalQaIterations,
840→            // Token breakdown (AC-6)
841→            inputTokens: tokenUsage.inputTokens || undefined,
842→            outputTokens: tokenUsage.outputTokens || undefined,
843→            cacheTokens: tokenUsage.cacheTokens || undefined,
844→          },
845→        });
846→
847→        if (config.verbose) {
848→          console.log(
849→            chalk.gray(`  📊 Metrics recorded to .sequant/metrics.json`),
850→          );
851→        }
852→      } catch (metricsError) {
853→        // Metrics recording errors shouldn't stop execution
854→        if (config.verbose) {
855→          console.log(
856→            chalk.yellow(`  ⚠️  Metrics recording error: ${metricsError}`),
857→          );
858→        }
859→      }
860→    }
861→
862→    // Summary
863→    console.log("\n" + ui.divider());
864→    console.log(colors.info("  Summary"));
865→    console.log(ui.divider());
866→
867→    console.log(
868→      colors.muted(
869→        `\n  Results: ${colors.success(`${passed} passed`)}, ${colors.error(`${failed} failed`)}`,
870→      ),
871→    );
872→
873→    for (const result of results) {
874→      const status = result.success
875→        ? ui.statusIcon("success")
876→        : ui.statusIcon("error");
877→      const duration = result.durationSeconds
878→        ? colors.muted(` (${formatDuration(result.durationSeconds)})`)
879→        : "";
880→      const phases = result.phaseResults
881→        .map((p) =>
882→          p.success ? colors.success(p.phase) : colors.error(p.phase),
883→        )
884→        .join(" → ");
885→      const loopInfo = result.loopTriggered ? colors.warning(" [loop]") : "";
886→      const prInfo = result.prUrl
887→        ? colors.muted(` → PR #${result.prNumber}`)
888→        : "";
889→      console.log(
890→        `  ${status} #${result.issueNumber}: ${phases}${loopInfo}${prInfo}${duration}`,
891→      );
892→    }
893→
894→    console.log("");
895→
896→    if (logPath) {
897→      console.log(colors.muted(`  📝 Log: ${logPath}`));
898→      console.log("");
899→    }
900→
901→    // Reflection analysis (--reflect flag)
902→    if (mergedOptions.reflect && results.length > 0) {
903→      const reflection = analyzeRun({
904→        results,
905→        issueInfoMap,
906→        runLog: logWriter?.getRunLog() ?? null,
907→        config: {
908→          phases: config.phases,
909→          qualityLoop: config.qualityLoop,
910→        },
911→      });
912→      const reflectionOutput = formatReflection(reflection);
913→      if (reflectionOutput) {
914→        console.log(reflectionOutput);
915→        console.log("");
916→      }
917→    }
918→
919→    // Suggest merge checks for multi-issue batches
920→    if (results.length > 1 && passed > 0 && !config.dryRun) {
921→      console.log(
922→        colors.muted("  💡 Verify batch integration before merging:"),
923→      );
924→      console.log(colors.muted("     sequant merge --check"));
925→      console.log("");
926→    }
927→
928→    if (config.dryRun) {
929→      console.log(
930→        colors.warning(
931→          "  ℹ️  This was a dry run. Use without --dry-run to execute.",
932→        ),
933→      );
934→      console.log("");
935→    }
936→
937→    // Set exit code if any failed
938→    if (failed > 0 && !config.dryRun) {
939→      exitCode = 1;
940→    }
941→  } finally {
942→    // Always dispose shutdown manager to clean up signal handlers
943→    shutdown.dispose();
944→  }
945→
946→  // Exit with error if any failed (outside try/finally so dispose() runs first)
947→  if (exitCode !== 0) {
948→    process.exit(exitCode);
949→  }
950→}
951→

