118→export async function getIssueInfo(
119→  issueNumber: number,
120→): Promise<{ title: string; labels: string[] }> {
121→  try {
122→    const result = spawnSync(
123→      "gh",
124→      ["issue", "view", String(issueNumber), "--json", "title,labels"],
125→      { stdio: "pipe" },
126→    );
127→
128→    if (result.status === 0) {
129→      const data = JSON.parse(result.stdout.toString());
130→      return {
131→        title: data.title || `Issue #${issueNumber}`,
132→        labels: Array.isArray(data.labels)
133→          ? data.labels.map((l: { name: string }) => l.name)
134→          : [],
135→      };
136→    }
137→  } catch {
138→    // Ignore errors, use defaults
139→  }
140→
141→  return { title: `Issue #${issueNumber}`, labels: [] };
142→}
143→
144→/**
145→ * Parse dependencies from issue body and labels
146→ * Returns array of issue numbers this issue depends on
147→ */
148→export function parseDependencies(issueNumber: number): number[] {
149→  try {
150→    const result = spawnSync(
151→      "gh",
152→      ["issue", "view", String(issueNumber), "--json", "body,labels"],
153→      { stdio: "pipe" },
154→    );
155→
156→    if (result.status !== 0) return [];
157→
158→    const data = JSON.parse(result.stdout.toString());
159→    const dependencies: number[] = [];
160→
161→    // Parse from body: "Depends on: #123" or "**Depends on**: #123"
162→    if (data.body) {
163→      const bodyMatch = data.body.match(
164→        /\*?\*?depends\s+on\*?\*?:?\s*#?(\d+)/gi,
165→      );
166→      if (bodyMatch) {
167→        for (const match of bodyMatch) {
168→          const numMatch = match.match(/(\d+)/);
169→          if (numMatch) {
170→            dependencies.push(parseInt(numMatch[1], 10));
171→          }
172→        }
173→      }
174→    }
175→
176→    // Parse from labels: "depends-on/123" or "depends-on-123"
177→    if (data.labels && Array.isArray(data.labels)) {
178→      for (const label of data.labels) {
179→        const labelName = label.name || label;
180→        const labelMatch = labelName.match(/depends-on[-/](\d+)/i);
181→        if (labelMatch) {
182→          dependencies.push(parseInt(labelMatch[1], 10));
183→        }
184→      }
185→    }
186→
187→    return [...new Set(dependencies)]; // Remove duplicates
188→  } catch {
189→    return [];
190→  }
191→}
192→
193→/**
194→ * Sort issues by dependencies (topological sort)
195→ * Issues with no dependencies come first, then issues that depend on them
196→ */
197→export function sortByDependencies(issueNumbers: number[]): number[] {
198→  // Build dependency graph
199→  const dependsOn = new Map<number, number[]>();
200→  for (const issue of issueNumbers) {
201→    const deps = parseDependencies(issue);
202→    // Only include dependencies that are in our issue list
203→    dependsOn.set(
204→      issue,
205→      deps.filter((d) => issueNumbers.includes(d)),
206→    );
207→  }
208→
209→  // Topological sort using Kahn's algorithm
210→  const inDegree = new Map<number, number>();
211→  for (const issue of issueNumbers) {
212→    inDegree.set(issue, 0);
213→  }
214→  for (const deps of dependsOn.values()) {
215→    for (const dep of deps) {
216→      inDegree.set(dep, (inDegree.get(dep) || 0) + 1);
217→    }
218→  }
219→
220→  // Note: inDegree counts how many issues depend on each issue
221→  // We want to process issues that nothing depends on last
222→  // So we sort by: issues nothing depends on first, then dependent issues
223→  const sorted: number[] = [];
224→  const queue: number[] = [];
225→
226→  // Start with issues that have no dependencies
227→  for (const issue of issueNumbers) {
228→    const deps = dependsOn.get(issue) || [];
229→    if (deps.length === 0) {
230→      queue.push(issue);
231→    }
232→  }
233→
234→  const visited = new Set<number>();
235→  while (queue.length > 0) {
236→    const issue = queue.shift()!;
237→    if (visited.has(issue)) continue;
238→    visited.add(issue);
239→    sorted.push(issue);
240→
241→    // Find issues that depend on this one
242→    for (const [other, deps] of dependsOn.entries()) {
243→      if (deps.includes(issue) && !visited.has(other)) {
244→        // Check if all dependencies of 'other' are satisfied
245→        const allDepsSatisfied = deps.every((d) => visited.has(d));
246→        if (allDepsSatisfied) {
247→          queue.push(other);
248→        }
249→      }
250→    }
251→  }
252→
253→  // Add any remaining issues (circular dependencies or unvisited)
254→  for (const issue of issueNumbers) {
255→    if (!visited.has(issue)) {
256→      sorted.push(issue);
257→    }
258→  }
259→
260→  return sorted;
261→}
