263→/**
264→ * Parse batch arguments into groups of issues
265→ */
266→export function parseBatches(batchArgs: string[]): number[][] {
267→  return batchArgs.map((batch) =>
268→    batch
269→      .split(/\s+/)
270→      .map((n) => parseInt(n, 10))
271→      .filter((n) => !isNaN(n)),
272→  );
273→}
