303→export async function executeBatch(
304→  issueNumbers: number[],
305→  config: ExecutionConfig,
306→  logWriter: LogWriter | null,
307→  stateManager: StateManager | null,
308→  options: RunOptions,
309→  issueInfoMap: Map<number, { title: string; labels: string[] }>,
310→  worktreeMap: Map<number, WorktreeInfo>,
311→  shutdownManager?: ShutdownManager,
312→  packageManager?: string,
313→  baseBranch?: string,
314→): Promise<IssueResult[]> {
315→  const results: IssueResult[] = [];
316→
317→  for (const issueNumber of issueNumbers) {
318→    // Check if shutdown was triggered
319→    if (shutdownManager?.shuttingDown) {
320→      break;
321→    }
322→
323→    const issueInfo = issueInfoMap.get(issueNumber) ?? {
324→      title: `Issue #${issueNumber}`,
325→      labels: [],
326→    };
327→    const worktreeInfo = worktreeMap.get(issueNumber);
328→
329→    // Start issue logging
330→    if (logWriter) {
331→      logWriter.startIssue(issueNumber, issueInfo.title, issueInfo.labels);
332→    }
333→
334→    const result = await runIssueWithLogging(
335→      issueNumber,
336→      config,
337→      logWriter,
338→      stateManager,
339→      issueInfo.title,
340→      issueInfo.labels,
341→      options,
342→      worktreeInfo?.path,
343→      worktreeInfo?.branch,
344→      shutdownManager,
345→      false, // Batch mode doesn't support chain
346→      packageManager,
347→      undefined,
348→      baseBranch,
349→    );
350→    results.push(result);
351→
352→    // Record PR info in log before completing issue
353→    if (logWriter && result.prNumber && result.prUrl) {
354→      logWriter.setPRInfo(result.prNumber, result.prUrl);
355→    }
356→
357→    // Complete issue logging
358→    if (logWriter) {
359→      logWriter.completeIssue();
360→    }
361→  }
362→
363→  return results;
364→}
