366→export async function runIssueWithLogging(
367→  issueNumber: number,
368→  config: ExecutionConfig,
369→  logWriter: LogWriter | null,
370→  stateManager: StateManager | null,
371→  issueTitle: string,
372→  labels: string[],
373→  options: RunOptions,
374→  worktreePath?: string,
375→  branch?: string,
376→  shutdownManager?: ShutdownManager,
377→  chainMode?: boolean,
378→  packageManager?: string,
379→  isLastInChain?: boolean,
380→  baseBranch?: string,
381→): Promise<IssueResult> {
382→  const startTime = Date.now();
383→  const phaseResults: PhaseResult[] = [];
384→  let loopTriggered = false;
385→  let sessionId: string | undefined;
386→
387→  console.log(chalk.blue(`\n  Issue #${issueNumber}`));
388→  if (worktreePath) {
389→    console.log(chalk.gray(`    Worktree: ${worktreePath}`));
390→  }
391→
392→  // Initialize state tracking for this issue
393→  if (stateManager) {
394→    try {
395→      const existingState = await stateManager.getIssueState(issueNumber);
396→      if (!existingState) {
397→        await stateManager.initializeIssue(issueNumber, issueTitle, {
398→          worktree: worktreePath,
399→          branch,
400→          qualityLoop: config.qualityLoop,
401→          maxIterations: config.maxIterations,
402→        });
403→      } else {
404→        // Update worktree info if it changed
405→        if (worktreePath && branch) {
406→          await stateManager.updateWorktreeInfo(
407→            issueNumber,
408→            worktreePath,
409→            branch,
410→          );
411→        }
412→      }
413→    } catch (error) {
414→      // State tracking errors shouldn't stop execution
415→      if (config.verbose) {
416→        console.log(chalk.yellow(`    ⚠️  State tracking error: ${error}`));
417→      }
418→    }
419→  }
420→
421→  // Determine phases for this specific issue
422→  let phases: Phase[];
423→  let detectedQualityLoop = false;
424→  let specAlreadyRan = false;
425→
426→  if (options.autoDetectPhases) {
427→    // Check if labels indicate a simple bug/fix (skip spec entirely)
428→    const lowerLabels = labels.map((l) => l.toLowerCase());
429→    const isSimpleBugFix = lowerLabels.some((label) =>
430→      BUG_LABELS.some((bugLabel) => label.includes(bugLabel)),
431→    );
432→
433→    if (isSimpleBugFix) {
434→      // Simple bug fix: skip spec, go straight to exec → qa
435→      phases = ["exec", "qa"];
436→      console.log(chalk.gray(`    Bug fix detected: ${phases.join(" → ")}`));
437→    } else {
438→      // Run spec first to get recommended workflow
439→      console.log(chalk.gray(`    Running spec to determine workflow...`));
440→
441→      // Create spinner for spec phase (1 of estimated 3: spec, exec, qa)
442→      const specSpinner = new PhaseSpinner({
443→        phase: "spec",
444→        phaseIndex: 1,
445→        totalPhases: 3, // Estimate; will be refined after spec
446→        shutdownManager,
447→      });
448→      specSpinner.start();
449→
450→      // Track spec phase start in state
451→      if (stateManager) {
452→        try {
453→          await stateManager.updatePhaseStatus(
454→            issueNumber,
455→            "spec",
456→            "in_progress",
457→          );
458→        } catch {
459→          // State tracking errors shouldn't stop execution
460→        }
461→      }
462→
463→      const specStartTime = new Date();
464→      // Note: spec runs in main repo (not worktree) for planning
465→      const specResult = await executePhaseWithRetry(
466→        issueNumber,
467→        "spec",
468→        config,
469→        sessionId,
470→        worktreePath, // Will be ignored for spec (non-isolated phase)
471→        shutdownManager,
472→        specSpinner,
473→      );
474→      const specEndTime = new Date();
475→
476→      if (specResult.sessionId) {
477→        sessionId = specResult.sessionId;
478→        // Update session ID in state for resume capability
479→        if (stateManager) {
480→          try {
481→            await stateManager.updateSessionId(
482→              issueNumber,
483→              specResult.sessionId,
484→            );
485→          } catch {
486→            // State tracking errors shouldn't stop execution
487→          }
488→        }
489→      }
490→
491→      phaseResults.push(specResult);
492→      specAlreadyRan = true;
493→
494→      // Log spec phase result
495→      // Note: Spec runs in main repo, not worktree, so no git diff stats
496→      if (logWriter) {
497→        const phaseLog = createPhaseLogFromTiming(
498→          "spec",
499→          issueNumber,
500→          specStartTime,
501→          specEndTime,
502→          specResult.success
503→            ? "success"
504→            : specResult.error?.includes("Timeout")
505→              ? "timeout"
506→              : "failure",
507→          { error: specResult.error },
508→        );
509→        logWriter.logPhase(phaseLog);
510→      }
511→
512→      // Track spec phase completion in state
513→      if (stateManager) {
514→        try {
515→          const phaseStatus = specResult.success ? "completed" : "failed";
516→          await stateManager.updatePhaseStatus(
517→            issueNumber,
518→            "spec",
519→            phaseStatus,
520→            {
521→              error: specResult.error,
522→            },
523→          );
524→        } catch {
525→          // State tracking errors shouldn't stop execution
526→        }
527→      }
528→
529→      if (!specResult.success) {
530→        specSpinner.fail(specResult.error);
531→        const durationSeconds = (Date.now() - startTime) / 1000;
532→        return {
533→          issueNumber,
534→          success: false,
535→          phaseResults,
536→          durationSeconds,
537→          loopTriggered: false,
538→        };
539→      }
540→
541→      specSpinner.succeed();
542→
543→      // Parse recommended workflow from spec output
544→      const parsedWorkflow = specResult.output
545→        ? parseRecommendedWorkflow(specResult.output)
546→        : null;
547→
548→      if (parsedWorkflow) {
549→        // Remove spec from phases since we already ran it
550→        phases = parsedWorkflow.phases.filter((p) => p !== "spec");
551→        detectedQualityLoop = parsedWorkflow.qualityLoop;
552→        console.log(
553→          chalk.gray(
554→            `    Spec recommends: ${phases.join(" → ")}${detectedQualityLoop ? " (quality loop)" : ""}`,
555→          ),
556→        );
557→      } else {
558→        // Fall back to label-based detection
559→        console.log(
560→          chalk.yellow(
561→            `    Could not parse spec recommendation, using label-based detection`,
562→          ),
563→        );
564→        const detected = detectPhasesFromLabels(labels);
565→        phases = detected.phases.filter((p) => p !== "spec");
566→        detectedQualityLoop = detected.qualityLoop;
567→        console.log(chalk.gray(`    Fallback: ${phases.join(" → ")}`));
568→      }
569→    }
570→  } else {
571→    // Use explicit phases with adjustments
572→    phases = determinePhasesForIssue(config.phases, labels, options);
573→    if (phases.length !== config.phases.length) {
574→      console.log(chalk.gray(`    Phases adjusted: ${phases.join(" → ")}`));
575→    }
576→  }
577→
578→  // Resume: filter out completed phases if --resume flag is set
579→  if (options.resume) {
580→    const resumeResult = filterResumedPhases(issueNumber, phases, true);
581→    if (resumeResult.skipped.length > 0) {
582→      console.log(
583→        chalk.gray(
584→          `    Resume: skipping completed phases: ${resumeResult.skipped.join(", ")}`,
585→        ),
586→      );
587→      phases = resumeResult.phases;
588→    }
589→    // Also skip spec if it was auto-detected as completed
590→    if (
591→      specAlreadyRan &&
592→      resumeResult.skipped.length === 0 &&
593→      resumeResult.phases.length === 0
594→    ) {
595→      console.log(chalk.gray(`    Resume: all phases already completed`));
596→    }
597→  }
598→
599→  // Add testgen phase if requested (and spec was in the phases)
600→  if (
601→    options.testgen &&
602→    (phases.includes("spec") || specAlreadyRan) &&
603→    !phases.includes("testgen")
604→  ) {
605→    // Insert testgen at the beginning if spec already ran, otherwise after spec
606→    if (specAlreadyRan) {
607→      phases.unshift("testgen");
608→    } else {
609→      const specIndex = phases.indexOf("spec");
610→      if (specIndex !== -1) {
611→        phases.splice(specIndex + 1, 0, "testgen");
612→      }
613→    }
614→  }
615→
616→  let iteration = 0;
617→  const useQualityLoop = config.qualityLoop || detectedQualityLoop;
618→  const maxIterations = useQualityLoop ? config.maxIterations : 1;
619→  let completedSuccessfully = false;
620→
621→  while (iteration < maxIterations) {
622→    iteration++;
623→
624→    if (useQualityLoop && iteration > 1) {
625→      console.log(
626→        chalk.yellow(
627→          `    Quality loop iteration ${iteration}/${maxIterations}`,
628→        ),
629→      );
630→      loopTriggered = true;
631→    }
632→
633→    let phasesFailed = false;
634→
635→    // Calculate total phases for progress indicator
636→    // If spec already ran in auto-detect mode, it's counted separately
637→    const totalPhases = specAlreadyRan ? phases.length + 1 : phases.length;
638→    const phaseIndexOffset = specAlreadyRan ? 1 : 0;
639→
640→    for (let phaseIdx = 0; phaseIdx < phases.length; phaseIdx++) {
641→      const phase = phases[phaseIdx];
642→      const phaseNumber = phaseIdx + 1 + phaseIndexOffset;
643→
644→      // Create spinner for this phase
645→      const phaseSpinner = new PhaseSpinner({
646→        phase,
647→        phaseIndex: phaseNumber,
648→        totalPhases,
649→        shutdownManager,
650→        iteration: useQualityLoop ? iteration : undefined,
651→      });
652→      phaseSpinner.start();
653→
654→      // Track phase start in state
655→      if (stateManager) {
656→        try {
657→          await stateManager.updatePhaseStatus(
658→            issueNumber,
659→            phase as StatePhase,
660→            "in_progress",
661→          );
662→        } catch {
663→          // State tracking errors shouldn't stop execution
664→        }
665→      }
666→
667→      const phaseStartTime = new Date();
668→      const result = await executePhaseWithRetry(
669→        issueNumber,
670→        phase,
671→        config,
672→        sessionId,
673→        worktreePath,
674→        shutdownManager,
675→        phaseSpinner,
676→      );
677→      const phaseEndTime = new Date();
678→
679→      // Capture session ID for subsequent phases
680→      if (result.sessionId) {
681→        sessionId = result.sessionId;
682→        // Update session ID in state for resume capability
683→        if (stateManager) {
684→          try {
685→            await stateManager.updateSessionId(issueNumber, result.sessionId);
686→          } catch {
687→            // State tracking errors shouldn't stop execution
688→          }
689→        }
690→      }
691→
692→      phaseResults.push(result);
693→
694→      // Log phase result with observability data (AC-1, AC-2, AC-3, AC-7)
695→      if (logWriter) {
696→        // Capture git diff stats for worktree phases (AC-1, AC-3)
697→        const diffStats = worktreePath
698→          ? getGitDiffStats(worktreePath, baseBranch)
699→          : undefined;
700→
701→        // Capture commit hash after phase (AC-2)
702→        const commitHash = worktreePath
703→          ? getCommitHash(worktreePath)
704→          : undefined;
705→
706→        // Read cache metrics for QA phase (AC-7)
707→        const cacheMetrics =
708→          phase === "qa" ? readCacheMetrics(worktreePath) : undefined;
709→
710→        const phaseLog = createPhaseLogFromTiming(
711→          phase,
712→          issueNumber,
713→          phaseStartTime,
714→          phaseEndTime,
715→          result.success
716→            ? "success"
717→            : result.error?.includes("Timeout")
718→              ? "timeout"
719→              : "failure",
720→          {
721→            error: result.error,
722→            verdict: result.verdict,
723→            // Observability fields (AC-1, AC-2, AC-3, AC-7)
724→            filesModified: diffStats?.filesModified,
725→            fileDiffStats: diffStats?.fileDiffStats,
726→            commitHash,
727→            cacheMetrics,
728→          },
729→        );
730→        logWriter.logPhase(phaseLog);
731→      }
732→
733→      // Track phase completion in state
734→      if (stateManager) {
735→        try {
736→          const phaseStatus = result.success
737→            ? "completed"
738→            : result.error?.includes("Timeout")
739→              ? "failed"
740→              : "failed";
741→          await stateManager.updatePhaseStatus(
742→            issueNumber,
743→            phase as StatePhase,
744→            phaseStatus,
745→            { error: result.error },
746→          );
747→        } catch {
748→          // State tracking errors shouldn't stop execution
749→        }
750→      }
751→
752→      if (result.success) {
753→        phaseSpinner.succeed();
754→      } else {
755→        phaseSpinner.fail(result.error);
756→        phasesFailed = true;
757→
758→        // If quality loop enabled, run loop phase to fix issues
759→        if (useQualityLoop && iteration < maxIterations) {
760→          // Create spinner for loop phase
761→          const loopSpinner = new PhaseSpinner({
762→            phase: "loop",
763→            phaseIndex: phaseNumber,
764→            totalPhases,
765→            shutdownManager,
766→            iteration,
767→          });
768→          loopSpinner.start();
769→
770→          const loopResult = await executePhaseWithRetry(
771→            issueNumber,
772→            "loop",
773→            config,
774→            sessionId,
775→            worktreePath,
776→            shutdownManager,
777→            loopSpinner,
778→          );
779→          phaseResults.push(loopResult);
780→
781→          if (loopResult.sessionId) {
782→            sessionId = loopResult.sessionId;
783→          }
784→
785→          if (loopResult.success) {
786→            loopSpinner.succeed();
787→            // Continue to next iteration
788→            break;
789→          } else {
790→            loopSpinner.fail(loopResult.error);
791→          }
792→        }
793→
794→        // Stop on first failure (if not in quality loop or loop failed)
795→        break;
796→      }
797→    }
798→
799→    // If all phases passed, exit the loop
800→    if (!phasesFailed) {
801→      completedSuccessfully = true;
802→      break;
803→    }
804→
805→    // If we're not in quality loop mode, don't retry
806→    if (!config.qualityLoop) {
807→      break;
808→    }
809→  }
810→
811→  const durationSeconds = (Date.now() - startTime) / 1000;
812→  // Success is determined by whether all phases completed in any iteration,
813→  // not whether all accumulated phase results passed (which would fail after loop recovery)
814→  const success = completedSuccessfully;
815→
816→  // Update final issue status in state
817→  if (stateManager) {
818→    try {
819→      const finalStatus = success ? "ready_for_merge" : "in_progress";
820→      await stateManager.updateIssueStatus(issueNumber, finalStatus);
821→    } catch {
822→      // State tracking errors shouldn't stop execution
823→    }
824→  }
825→
826→  // Create checkpoint commit in chain mode after QA passes
827→  if (success && chainMode && worktreePath) {
828→    createCheckpointCommit(worktreePath, issueNumber, config.verbose);
829→  }
830→
831→  // Rebase onto the base branch before PR creation (unless --no-rebase)
832→  // This ensures the branch is up-to-date and prevents lockfile drift
833→  // AC-1: Non-chain mode rebases onto the base branch before PR
834→  // AC-2: Chain mode rebases only the final branch onto the base branch before PR
835→  //        (intermediate branches must stay based on their predecessor)
836→  const shouldRebase =
837→    success &&
838→    worktreePath &&
839→    !options.noRebase &&
840→    (!chainMode || isLastInChain);
841→  if (shouldRebase) {
842→    rebaseBeforePR(
843→      worktreePath,
844→      issueNumber,
845→      packageManager,
846→      config.verbose,
847→      baseBranch,
848→    );
849→  }
850→
851→  // Create PR after successful QA + rebase (unless --no-pr)
852→  let prNumber: number | undefined;
853→  let prUrl: string | undefined;
854→  const shouldCreatePR = success && worktreePath && branch && !options.noPr;
855→  if (shouldCreatePR) {
856→    const prResult = createPR(
857→      worktreePath,
858→      issueNumber,
859→      issueTitle,
860→      branch,
861→      config.verbose,
862→      labels,
863→    );
864→    if (prResult.success && prResult.prNumber && prResult.prUrl) {
865→      prNumber = prResult.prNumber;
866→      prUrl = prResult.prUrl;
867→
868→      // Update workflow state with PR info
869→      if (stateManager) {
870→        try {
871→          await stateManager.updatePRInfo(issueNumber, {
872→            number: prResult.prNumber,
873→            url: prResult.prUrl,
874→          });
875→        } catch {
876→          // State tracking errors shouldn't stop execution
877→        }
878→      }
879→    }
880→  }
881→
882→  return {
883→    issueNumber,
884→    success,
885→    phaseResults,
886→    durationSeconds,
887→    loopTriggered,
888→    prNumber,
889→    prUrl,
890→  };
891→}
