  1→/**
  2→ * Log writer for structured workflow run logs
  3→ *
  4→ * Writes JSON logs to disk for analysis and debugging.
  5→ *
  6→ * @example
  7→ * ```typescript
  8→ * import { LogWriter } from './log-writer';
  9→ *
 10→ * const writer = new LogWriter({ projectPath: '.sequant/logs' });
 11→ * await writer.initialize(config);
 12→ * await writer.logPhase(phaseLog);
 13→ * await writer.finalize();
 14→ * ```
 15→ */
 16→
 17→import * as fs from "fs";
 18→import * as path from "path";
 19→import * as os from "os";
 20→import {
 21→  type RunLog,
 22→  type RunConfig,
 23→  type IssueLog,
 24→  type PhaseLog,
 25→  type Phase,
 26→  type IssueStatus,
 27→  createEmptyRunLog,
 28→  finalizeRunLog,
 29→  generateLogFilename,
 30→  LOG_PATHS,
 31→} from "./run-log-schema.js";
 32→import {
 33→  rotateIfNeeded,
 34→  type RotationSettings,
 35→  DEFAULT_ROTATION_SETTINGS,
 36→} from "./log-rotation.js";
 37→
 38→export interface LogWriterOptions {
 39→  /** Path to log directory (default: .sequant/logs in current directory) */
 40→  logPath?: string;
 41→  /** Whether to also write to user-level logs */
 42→  writeToUserLogs?: boolean;
 43→  /** Enable verbose logging */
 44→  verbose?: boolean;
 45→  /** Log rotation settings */
 46→  rotation?: RotationSettings;
 47→  /** Git commit SHA at run start (AC-2) */
 48→  startCommit?: string;
 49→}
 50→
 51→/**
 52→ * Manages writing structured run logs to disk
 53→ */
 54→export class LogWriter {
 55→  private runLog: Omit<RunLog, "endTime"> | null = null;
 56→  private currentIssue: Partial<IssueLog> | null = null;
 57→  private logPath: string;
 58→  private writeToUserLogs: boolean;
 59→  private verbose: boolean;
 60→  private rotation: RotationSettings;
 61→  private startCommit?: string;
 62→
 63→  constructor(options: LogWriterOptions = {}) {
 64→    this.logPath = options.logPath ?? LOG_PATHS.project;
 65→    this.writeToUserLogs = options.writeToUserLogs ?? false;
 66→    this.verbose = options.verbose ?? false;
 67→    this.rotation = options.rotation ?? DEFAULT_ROTATION_SETTINGS;
 68→    this.startCommit = options.startCommit;
 69→  }
 70→
 71→  /**
 72→   * Initialize a new run log
 73→   *
 74→   * @param config - Run configuration
 75→   */
 76→  async initialize(config: RunConfig): Promise<void> {
 77→    this.runLog = createEmptyRunLog(config, { startCommit: this.startCommit });
 78→
 79→    // Ensure log directory exists
 80→    await this.ensureLogDirectory(this.logPath);
 81→
 82→    if (this.writeToUserLogs) {
 83→      const userPath = LOG_PATHS.user.replace("~", os.homedir());
 84→      await this.ensureLogDirectory(userPath);
 85→    }
 86→
 87→    if (this.verbose && this.runLog) {
 88→      console.log(`📝 Log initialized: ${this.runLog.runId}`);
 89→    }
 90→  }
 91→
 92→  /**
 93→   * Start logging a new issue
 94→   *
 95→   * @param issueNumber - GitHub issue number
 96→   * @param title - Issue title
 97→   * @param labels - Issue labels
 98→   */
 99→  startIssue(issueNumber: number, title: string, labels: string[]): void {
100→    if (!this.runLog) {
101→      throw new Error("LogWriter not initialized. Call initialize() first.");
102→    }
103→
104→    this.currentIssue = {
105→      issueNumber,
106→      title,
107→      labels,
108→      phases: [],
109→      status: "success" as IssueStatus,
110→      totalDurationSeconds: 0,
111→    };
112→
113→    if (this.verbose) {
114→      console.log(`📝 Started logging issue #${issueNumber}`);
115→    }
116→  }
117→
118→  /**
119→   * Log a completed phase
120→   *
121→   * @param phaseLog - Complete phase log entry
122→   */
123→  logPhase(phaseLog: PhaseLog): void {
124→    if (!this.currentIssue) {
125→      throw new Error("No current issue. Call startIssue() first.");
126→    }
127→
128→    this.currentIssue.phases = [...(this.currentIssue.phases ?? []), phaseLog];
129→
130→    // Update issue status based on phase result
131→    if (phaseLog.status === "failure") {
132→      this.currentIssue.status = "failure";
133→    } else if (
134→      phaseLog.status === "timeout" &&
135→      this.currentIssue.status !== "failure"
136→    ) {
137→      this.currentIssue.status = "partial";
138→    }
139→
140→    if (this.verbose) {
141→      console.log(
142→        `📝 Logged phase: ${phaseLog.phase} (${phaseLog.status}) - ${phaseLog.durationSeconds.toFixed(1)}s`,
143→      );
144→    }
145→  }
146→
147→  /**
148→   * Set PR info on the current issue (call before completeIssue)
149→   */
150→  setPRInfo(prNumber: number, prUrl: string): void {
151→    if (!this.currentIssue) {
152→      return;
153→    }
154→    this.currentIssue.prNumber = prNumber;
155→    this.currentIssue.prUrl = prUrl;
156→  }
157→
158→  /**
159→   * Complete the current issue and add it to the run log
160→   */
161→  completeIssue(): void {
162→    if (!this.runLog || !this.currentIssue) {
163→      throw new Error("No current issue to complete.");
164→    }
165→
166→    // Calculate total duration from phases
167→    const totalDurationSeconds =
168→      this.currentIssue.phases?.reduce(
169→        (sum: number, p: PhaseLog) => sum + p.durationSeconds,
170→        0,
171→      ) ?? 0;
172→
173→    const issueLog: IssueLog = {
174→      issueNumber: this.currentIssue.issueNumber!,
175→      title: this.currentIssue.title!,
176→      labels: this.currentIssue.labels!,
177→      status: this.currentIssue.status!,
178→      phases: this.currentIssue.phases!,
179→      totalDurationSeconds,
180→      ...(this.currentIssue.prNumber != null && {
181→        prNumber: this.currentIssue.prNumber,
182→      }),
183→      ...(this.currentIssue.prUrl != null && {
184→        prUrl: this.currentIssue.prUrl,
185→      }),
186→    };
187→
188→    this.runLog.issues.push(issueLog);
189→    this.currentIssue = null;
190→
191→    if (this.verbose) {
192→      console.log(
193→        `📝 Completed issue #${issueLog.issueNumber} (${issueLog.status})`,
194→      );
195→    }
196→  }
197→
198→  /**
199→   * Finalize the run log and write to disk
200→   *
201→   * Automatically rotates old logs if thresholds are exceeded.
202→   *
203→   * @param options - Optional finalization options
204→   * @param options.endCommit - Git commit SHA at run end (AC-2)
205→   * @returns Path to the written log file
206→   */
207→  async finalize(options?: { endCommit?: string }): Promise<string> {
208→    if (!this.runLog) {
209→      throw new Error("LogWriter not initialized.");
210→    }
211→
212→    // Complete any pending issue
213→    if (this.currentIssue) {
214→      this.completeIssue();
215→    }
216→
217→    const finalLog = finalizeRunLog(this.runLog, {
218→      endCommit: options?.endCommit,
219→    });
220→    const filename = generateLogFilename(
221→      finalLog.runId,
222→      new Date(finalLog.startTime),
223→    );
224→
225→    // Write to project logs
226→    const projectPath = path.join(this.resolvePath(this.logPath), filename);
227→    await this.writeLogFile(projectPath, finalLog);
228→
229→    // Optionally write to user logs
230→    if (this.writeToUserLogs) {
231→      const userPath = path.join(this.resolvePath(LOG_PATHS.user), filename);
232→      await this.writeLogFile(userPath, finalLog);
233→    }
234→
235→    if (this.verbose) {
236→      console.log(`📝 Log written: ${projectPath}`);
237→    }
238→
239→    // Auto-rotate if needed
240→    if (this.rotation.enabled) {
241→      const result = rotateIfNeeded(this.logPath, this.rotation);
242→      if (result.rotated && this.verbose) {
243→        console.log(
244→          `📝 Rotated ${result.deletedCount} old log(s), reclaimed ${(result.bytesReclaimed / 1024).toFixed(1)} KB`,
245→        );
246→      }
247→    }
248→
249→    return projectPath;
250→  }
251→
252→  /**
253→   * Get the current run log (for inspection)
254→   */
255→  getRunLog(): Omit<RunLog, "endTime"> | null {
256→    return this.runLog;
257→  }
258→
259→  /**
260→   * Get the run ID
261→   */
262→  getRunId(): string | null {
263→    return this.runLog?.runId ?? null;
264→  }
265→
266→  private resolvePath(logPath: string): string {
267→    return logPath.replace("~", os.homedir());
268→  }
269→
270→  private async ensureLogDirectory(logPath: string): Promise<void> {
271→    const resolved = this.resolvePath(logPath);
272→    if (!fs.existsSync(resolved)) {
273→      fs.mkdirSync(resolved, { recursive: true });
274→    }
275→  }
276→
277→  private async writeLogFile(filePath: string, log: RunLog): Promise<void> {
278→    const dir = path.dirname(filePath);
279→    if (!fs.existsSync(dir)) {
280→      fs.mkdirSync(dir, { recursive: true });
281→    }
282→    fs.writeFileSync(filePath, JSON.stringify(log, null, 2));
283→  }
284→}
285→
286→/**
287→ * Create a simple phase log from timing data
288→ *
289→ * Utility function for creating phase logs when you have start/end times.
290→ */
291→export function createPhaseLogFromTiming(
292→  phase: Phase,
293→  issueNumber: number,
294→  startTime: Date,
295→  endTime: Date,
