  const mockPhaseLog: PhaseLog = {
    phase: "spec",
    issueNumber: 123,
    startTime: "2024-01-15T10:00:00.000Z",
    endTime: "2024-01-15T10:01:30.000Z",
    durationSeconds: 90,
    status: "success",
  };

  beforeEach(() => {
