      writer.startIssue(123, "Test Issue", []);

      const timedOutPhase: PhaseLog = {
        ...mockPhaseLog,
        status: "timeout",
      };
      writer.logPhase(timedOutPhase);
      writer.completeIssue();

      const runLog = writer.getRunLog();
      expect(runLog!.issues[0].status).toBe("partial");
    });

