      writer.startIssue(123, "Test Issue", []);

      writer.logPhase(mockPhaseLog);

      expect(consoleSpy).toHaveBeenCalledWith(
        expect.stringContaining("Logged phase: spec (success)"),
      );
      consoleSpy.mockRestore();
    });
  });

